diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 2a1218a683ca..35b24e80a7a2 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -2522,6 +2522,18 @@ static Value *simplifyOrInst(Value *Op0, Value *Op1, const SimplifyQuery &Q,
       if (*Implied == true)
         return ConstantInt::getTrue(Op1->getType());
     }
+    if (std::optional<bool> Implied =
+            isImpliedCondition(Op0, Op1, Q.DL, true)) {
+      // If Op0 is true implies Op1 is true, then Op1 is a subset of Op0.
+      if (*Implied == true)
+        return Op1;
+    }
+    if (std::optional<bool> Implied =
+            isImpliedCondition(Op1, Op0, Q.DL, true)) {
+      // If Op1 is true implies Op0 is true, then Op0 is a subset of Op1.
+      if (*Implied == true)
+        return Op0;
+    }
   }

   if (Value *V = simplifyByDomEq(Instruction::Or, Op0, Op1, Q, MaxRecurse))
diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index 973943790c0a..bde4f093dc01 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -8292,7 +8292,25 @@ static std::optional<bool> isImpliedCondICmps(const ICmpInst *LHS,
   if (L0 == R0 && match(L1, m_APInt(LC)) && match(R1, m_APInt(RC)))
     return isImpliedCondCommonOperandWithConstants(LPred, *LC, RPred, *RC);

-  if (LPred == RPred)
+  // When L0 and R0 are the same 'add' instruction, and L1 and R1 are the two
+  // operands of that add, then unsigned less-than and greater-or-equal
+  // comparisons are equivalent. This is because both check for unsigned overflow
+  // of the addition:
+  //   icmp ult (add a, b), a  ⇔  icmp ult (add a, b), b
+  //   icmp uge (add a, b), a  ⇔  icmp uge (add a, b), b
+  if (L0 == R0) {
+    Value *AddOp0, *AddOp1;
+    if (match(L0, m_Add(m_Value(AddOp0), m_Value(AddOp1))) &&
+        ((L1 == AddOp0 && R1 == AddOp1) || (L1 == AddOp1 && R1 == AddOp0))) {
+      if ((LPred == ICmpInst::ICMP_ULT && RPred == ICmpInst::ICMP_ULT) ||
+          (LPred == ICmpInst::ICMP_UGE && RPred == ICmpInst::ICMP_UGE))
+        return true;
+      if ((LPred == ICmpInst::ICMP_ULT && RPred == ICmpInst::ICMP_UGE) ||
+          (LPred == ICmpInst::ICMP_UGE && RPred == ICmpInst::ICMP_ULT))
+        return false;
+    }
+  }
+
     return isImpliedCondOperands(LPred, L0, L1, R0, R1, DL, Depth);

   return std::nullopt;
